mapper.select:
SELECT a.id, a.model_name modelName, a.model_content modelContent, a.model_text modelText, a.model_type modelType, (SELECT COUNT(*) FROM code_model_history b WHERE b.model_id = a.id
AND a.tenant_id = #{tenantId} ) useNum, a.create_id createId, CONVERT(a.create_time, char) createTime, a.last_update_id lastUpdateId, CONVERT(a.last_update_time, char) lastUpdateTime FROM code_model a WHERE a.group_id = #{groupId}
AND a.tenant_id = #{tenantId}
ORDER BY a.create_time DESC

SELECT
	a.id,
	a.model_name modelName
FROM
	code_model a
WHERE a.group_id = #{groupId}
AND a.model_name = #{modelName}
AND a.model_type = #{modelType}

	AND a.tenant_id = #{tenantId}

mapper.delete:
DELETE
FROM
	code_model
WHERE id = #{id}

	AND tenant_id = #{tenantId}

mapper.select:
SELECT
	a.id,
	a.model_name modelName
FROM
	code_model a
WHERE a.id != #{id}
AND a.group_id = #{groupId}
AND a.model_name = #{modelName}
AND a.model_type = #{modelType}

	AND a.tenant_id = #{tenantId}

mapper.update:
UPDATE code_model


		model_name = #{modelName},


		model_content = #{modelContent},


		model_text = #{modelText},

	model_type = #{modelType},
	last_update_id = #{lastUpdateId},
	last_update_time = #{lastUpdateTime}

WHERE id = #{id}

	AND tenant_id = #{tenantId}
